    "summary": "paipan: { title: '八字排盘方法'  content: [ \"排盘分四步：排年柱→排月柱→排日柱→排时柱\"  \"每柱由天干+地支组成 共四柱八字...",
    "content": "// ═══════════════════════════════════════════════════════\n// 二、排盘方法\n// ═══════════════════════════════════════════════════════\n\npaipan: {\n  title: '八字排盘方法',\n  content: [\n    \"排盘分四步：排年柱→排月柱→排日柱→排时柱\",\n    \"每柱由天干+地支组成，共四柱八字。\"\n  ],\n  nianzhu: {\n    title: '年柱',\n    steps: [\n      \"年柱以立春为界：立春前属前一年，立春后属新一年。\",\n      \"如2026年立春2月4日出生，在此日期之前使用2025年干支，之后使用2026年干支。\",\n      \"年干支按六十甲子顺序循环，每60年一个周期。例如2024年为甲辰年，2025年为乙巳年，2026年为丙午年。\"\n    ]\n  },\n  yuezhu: {\n    title: '月柱',\n    steps: [\n      \"月柱以节气为分界，二十四节气中「节」为准（立春、惊蛰、清明、立夏、芒种、小暑、立秋、白露、寒露、立冬、大雪、小寒）。\",\n      \"正月立春→惊蛰，二月惊蛰→清明，三月清明→立夏，四月立夏→芒种，五月芒种→小暑，六月小暑→立秋，七月立秋→白露，八月白露→寒露，九月寒露→立冬，十月立冬→大雪，冬月大雪→小寒，腊月小寒→立春。\",\n      \"月干推算：甲己之年丙作首，乙庚之岁戊为头，丙辛之年从庚起，丁壬壬寅顺水流，若问戊癸何处起，甲寅之上好追求。\"\n    ]\n  },\n  rizhu: {\n    title: '日柱',\n    steps: [\n      \"日柱需按公历日期精确计算，公式较复杂。\",\n      \"一般方法：已知1900年1月1日为甲子日，然后逐日推算。\",\n      \"简易做法：使用万年历或专业软件查表，或使用1900-2100年日柱计算公式。\",\n      \"日干为命主本人，是整个八字分析的基准点。\"\n    ]\n  },\n  shizhu: {\n    title: '时柱',\n    steps: [\n      \"时柱按出生时辰的地支确定（子时23-1，丑时1-3，寅时3-5，卯时5-7，辰时7-9，巳时9-11，午时11-13，未时13-15，申时15-17，酉时17-19，戌时19-21，亥时21-23）。\",\n      \"时干推算：甲己还加甲，乙庚丙作初，丙辛从戊起，丁壬庚子居，戊癸何方发，壬子是真途。\",\n      \"子时需注意：23-24点为晚子时，0-1点为早子时，前者日柱用当天，后者日柱用次日。\"\n    ]\n  }\n},",
