    "summary": "koujue: { title: '八字命理口诀'  jichu: [ \"一禄胜千财 二禄自然来\"  \"财库喜冲不喜合 冲开财库钱财多\"  \"伤官见官 为祸百端...",
    "content": "// ═══════════════════════════════════════════════════════\n// 十一、八字口诀精选\n// ═══════════════════════════════════════════════════════\n\nkoujue: {\n  title: '八字命理口诀',\n  jichu: [\n    \"一禄胜千财，二禄自然来\",\n    \"财库喜冲不喜合，冲开财库钱财多\",\n    \"伤官见官，为祸百端\",\n    \"印绶重重，必主孤寒\",\n    \"官星怕被合，被合必失职\",\n    \"七杀有制化为权，七杀无制必伤身\",\n    \"财多身弱，富屋贫人\",\n    \"身旺无依，离祖成家\",\n    \"印旺身强，福寿绵长\",\n    \"用神得长生，一生福禄增\"\n  ],\n  yongji: [\n    \"用神不可伤，伤之大不祥\",\n    \"忌神不可扶，扶之大祸出\",\n    \"用神旺而有力，富贵唾手可得\",\n    \"忌神旺而无制，贫贱在所难免\",\n    \"用神在日时，中年后发福\",\n    \"忌神在月令，一生负重担\",\n    \"用神得生扶，遇难必有助\",\n    \"用神逢冲克，好事多磨折\",\n    \"用神宜透干，忌神宜藏支\",\n    \"用神藏支深，大运引出成\"\n  ],\n  shixiang: [\n    \"财星入墓，必定破产\",\n    \"官星入墓，官运不通\",\n    \"印星入墓，求学受阻\",\n    \"比劫入墓，手足遭殃\",\n    \"长生最吉，衰病死墓为凶\",\n    \"阳干逢刃帝旺为上，阴干逢库沐浴为佳\"\n  ],\n  hunyin_jue: [\n    \"女命官星为夫，清纯不杂最为贵\",\n    \"男命财星为妻，一财一位福自随\",\n    \"官杀混杂女命愁，感情复杂难到头\",\n    \"财星被夺男命苦，破财婚变两相忧\",\n    \"日支逢冲婚姻动，不是分离也变心\",\n    \"日柱天地合，夫妻恩爱老来乐\"\n  ],\n  liunian_jue: [\n    \"太岁当头坐，无灾也有祸\",\n    \"流年冲大运，变化如翻云\",\n    \"合太岁为喜，家中有喜事\",\n    \"冲太岁为凶，破财伤人口\",\n    \"用神临太岁，好事自然来\",\n    \"忌神临太岁，烦恼不请到\"\n  ]\n},",
