    "summary": "fengshuiMatch: { title: '八字与风水对应关系'  rules: [ \"八字缺木者 宜居住东方卧室 多使用绿色装饰。\"  \"八字缺火者 宜...",
    "content": "// ═══════════════════════════════════════════════════════\n// 十六、八字与风水对照\n// ═══════════════════════════════════════════════════════\n\nfengshuiMatch: {\n  title: '八字与风水对应关系',\n  rules: [\n    \"八字缺木者，宜居住东方卧室，多使用绿色装饰。\",\n    \"八字缺火者，宜居住南方卧室，多用红色、紫色装饰。\",\n    \"八字缺土者，宜选择通光好、空气流通的住宅。\",\n    \"八字缺金者，宜多使用白色、金属装饰。\",\n    \"八字缺水者，宜靠近水源或在家中放置鱼缸。\",\n    \"八字水过旺者，宜住宅高楼层、阳光充足。\",\n    \"八字木过旺者，宜简约风格，减少植物。\",\n    \"八字火过旺者，宜多用水元素、阴凉环境。\",\n    \"八字金过旺者，宜多使用柔和材质和暖色调。\",\n    \"八字土过旺者，宜多使用金属、玻璃材质。\"\n  ]\n},",
